import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import MovieCard from '../components/MovieCard';
import { moviesAPI } from '../utils/api';
import '../styles/Movies.css';

const Movies = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchMovies();
  }, []);

  const fetchMovies = async () => {
    try {
      const response = await moviesAPI.getAll();
      setMovies(response.data);
      setError('');
    } catch (error) {
      setError('Failed to load movies');
      console.error('Error fetching movies:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = (movieId) => {
    setMovies(movies.filter(movie => movie._id !== movieId));
  };

  const filteredMovies = filter === 'all' 
    ? movies 
    : movies.filter(movie => movie.status === filter);

  const stats = {
    total: movies.length,
    watched: movies.filter(m => m.status === 'watched').length,
    watching: movies.filter(m => m.status === 'watching').length,
    plan: movies.filter(m => m.status === 'plan to watch').length
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="movies-page">
      <div className="movies-container">
        <div className="movies-header">
          <h1>
            My <span className="highlight">Movie Watchlist</span>
          </h1>
          
          <div className="stats-container">
            <div className="stat-card">
              <span className="stat-value">{stats.total}</span>
              <span className="stat-label">Total</span>
            </div>
            <div className="stat-card">
              <span className="stat-value">{stats.watched}</span>
              <span className="stat-label">Watched</span>
            </div>
            <div className="stat-card">
              <span className="stat-value">{stats.watching}</span>
              <span className="stat-label">Watching</span>
            </div>
            <div className="stat-card">
              <span className="stat-value">{stats.plan}</span>
              <span className="stat-label">Plan to Watch</span>
            </div>
          </div>

          <div className="filter-container">
            <label>Filter by status:</label>
            <select value={filter} onChange={(e) => setFilter(e.target.value)}>
              <option value="all">All Movies</option>
              <option value="watched">Watched</option>
              <option value="watching">Watching</option>
              <option value="plan to watch">Plan to Watch</option>
            </select>
          </div>
        </div>

        {error && <div className="error-message">{error}</div>}

        {filteredMovies.length === 0 ? (
          <div className="no-movies">
            <p>No movies found. Start adding some!</p>
            <Link to="/movies/add" className="btn btn-primary">
              Add Your First Movie
            </Link>
          </div>
        ) : (
          <div className="movies-grid">
            {filteredMovies.map(movie => (
              <MovieCard 
                key={movie._id} 
                movie={movie} 
                onDelete={handleDelete}
              />
            ))}
          </div>
        )}
      </div>

      {/* Footer - точно как на главной странице */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <div className="footer-logo">
              <img src="/Filmery.png" alt="Watchlist Logo" className="footer-logo-img" />
              <h3>Filmery</h3>
            </div>
            <p>Your personal movie tracking companion. Never forget a great film again.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><Link to="/">Home</Link></li>
              <li><Link to="/movies">My Watchlist</Link></li>
              <li><Link to="/login">Login</Link></li>
              <li><Link to="/register">Register</Link></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Features</h4>
            <ul>
              <li>Track Movies</li>
              <li>Rate & Review</li>
              <li>Statistics</li>
              <li>Private Lists</li>
            </ul>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; 2026 Movie Watchlist. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default Movies;
